func startFakeDNSServer(traefikIP string) *dns.Server {
	srv := &dns.Server{
		Addr:		":5053",
		Net:		"udp",
		Handler:	&handler{traefikIP},
	}

	go func() {
		log.Info().Msg("Start a fake DNS server.")
		if err := srv.ListenAndServe(); err != nil {
			log.Fatal().Err(err).Msg("Failed to set udp listener")
		}
	}()

	return srv
}
